    "content": "{"content":"static void add_page_to_zone_llist(struct zone *zone, struct page *page,\n\t\t\t\t   unsigned int order)\n{\n\t/* Remember the order */\n\tpage->private = order;\n\t/* Add the page to the free list */\n\tllist_add(&page->pcp_llist, &zone->trylock_free_pages);\n}\n\nstatic void free_one_page(struct zone *zone, struct page *page,\n\t\t\t  unsigned long pfn, unsigned int order,\n\t\t\t  fpi_t fpi_flags)\n{\n\tstruct llist_head *llhead;\n\tunsigned long flags;\n\n\tif (unlikely(fpi_flags & FPI_TRYLOCK)) {\n\t\tif (!zone_trylock_irqsave(zone, flags)) {\n\t\t\tadd_page_to_zone_llist(zone, page, order);\n\t\t\treturn;\n\t\t}\n\t} else {\n\t\tzone_lock_irqsave(zone, flags);\n\t}\n\n\t/* The lock succeeded. Process deferred pages. */\n\tllhead = &zone->trylock_free_pages;\n\tif (unlikely(!llist_empty(llhead) && !(fpi_flags & FPI_TRYLOCK))) {\n\t\tstruct llist_node *llnode;\n\t\tstruct page *p, *tmp;\n\n\t\tllnode = llist_del_all(llhead);\n\t\tllist_for_each_entry_safe(p, tmp, llnode, pcp_llist) {\n\t\t\tunsigned int p_order = p->private;\n\n\t\t\tsplit_large_buddy(zone, p, page_to_pfn(p), p_order, fpi_flags);\n\t\t\t__count_vm_events(PGFREE, 1 << p_order);\n\t\t}\n\t}\n\tsplit_large_buddy(zone, page, pfn, order, fpi_flags);\n\tzone_unlock_irqrestore(zone, flags);\n\n\t__count_vm_events(PGFREE, 1 << order);\n}\n\nstatic void __free_pages_ok(struct page *page, unsigned int order,\n\t\t\t    fpi_t fpi_flags)\n{\n\tunsigned long pfn = page_to_pfn(page);\n\tstruct zone *zone = page_zone(page);\n\n\tif (__free_pages_prepare(page, order, fpi_flags))\n\t\tfree_one_page(zone, page, pfn, order, fpi_flags);\n}\n\nvoid __meminit __free_pages_core(struct page *page, unsigned int order,\n\t\tenum meminit_context context)\n{\n\tunsigned int nr_pages = 1 << order;\n\tstruct page *p = page;\n\tunsigned int loop;\n\n\t/*\n\t * When initializing the memmap, __init_single_page() sets the refcount\n\t * of all pages to 1 (\"allocated\"/\"not free\"). We have to set the\n\t * refcount of all involved pages to 0.\n\t *\n\t * Note that hotplugged memory pages are initialized to PageOffline().\n\t * Pages freed from memblock might be marked as reserved.\n\t */\n\tif (IS_ENABLED(CONFIG_MEMORY_HOTPLUG) &&\n\t    unlikely(context == MEMINIT_HOTPLUG)) {\n\t\tfor (loop = 0; loop < nr_pages; loop++, p++) {\n\t\t\tVM_WARN_ON_ONCE(PageReserved(p));\n\t\t\t__ClearPageOffline(p);\n\t\t\tset_page_count(p, 0);\n\t\t}\n\n\t\tadjust_managed_page_count(page, nr_pages);\n\t} else {\n\t\tfor (loop = 0; loop < nr_pages; loop++, p++) {\n\t\t\t__ClearPageReserved(p);\n\t\t\tset_page_count(p, 0);\n\t\t}\n\n\t\t/* memblock adjusts totalram_pages() manually. */\n\t\tatomic_long_add(nr_pages, &page_zone(page)->managed_pages);\n\t}\n\n\tif (page_contains_unaccepted(page, order)) {\n\t\tif (order == MAX_PAGE_ORDER && __free_unaccepted(page))\n\t\t\treturn;\n\n\t\taccept_memory(page_to_phys(page), PAGE_SIZE << order);\n\t}\n\n\t/*\n\t * Bypass PCP and place fresh pages right to the tail, primarily\n\t * relevant for memory onlining.\n\t */\n\t__free_pages_ok(page, order, FPI_TO_TAIL);\n}\n\n/*\n * Check that the whole (or subset of) a pageblock given by the interval of\n * [start_pfn, end_pfn) is valid and within the same zone, before scanning it\n * with the migration of free compaction scanner.\n *\n * Return struct page pointer of start_pfn, or NULL if checks were not passed.\n *\n * It's possible on some configurations to have a setup like node0 node1 node0\n * i.e. it's possible that all pages within a zones range of pages do not\n * belong to a single zone. We assume that a border between node0 and node1\n * can occur within a single pageblock, but not a node0 node1 node0\n * interleaving within a single pageblock. It is therefore sufficient to check\n * the first and last page of a pageblock and avoid checking each individual\n * page in a pageblock.\n *\n * Note: the function may return non-NULL struct page even for a page block\n * which contains a memory hole (i.e. there is no physical memory for a subset\n * of the pfn range). For example, if the pageblock order is MAX_PAGE_ORDER, which\n * will fall into 2 sub-sections, and the end pfn of the pageblock may be hole\n * even though the start pfn is online and valid. This should be safe most of\n * the time because struct pages are still initialized via init_unavailable_range()\n * and pfn walkers shouldn't touch any physical memory range for which they do\n * not recognize any specific metadata in struct pages.\n */\nstruct page *__pageblock_pfn_to_page(unsigned long start_pfn,\n\t\t\t\t     unsigned long end_pfn, struct zone *zone)\n{\n\tstruct page *start_page;\n\tstruct page *end_page;\n\n\t/* end_pfn is one past the range we are checking */\n\tend_pfn--;\n\n\tif (!pfn_valid(end_pfn))\n\t\treturn NULL;\n\n\tstart_page = pfn_to_online_page(start_pfn);\n\tif (!start_page)\n\t\treturn NULL;\n\n\tif (page_zone(start_page) != zone)\n\t\treturn NULL;\n\n\tend_page = pfn_to_page(end_pfn);\n\n\t/* This gives a shorter code than deriving page_zone(end_page) */\n\tif (page_zone_id(start_page) != page_zone_id(end_page))\n\t\treturn NULL;\n\n\treturn start_page;\n}\n\n/*\n * The order of subdivision here is critical for the IO subsystem.\n * Please do not alter this order without good reasons and regression\n * testing. Specifically, as large blocks of memory are subdivided,\n * the order in which smaller blocks are delivered depends on the order\n * they're subdivided in this function. This is the primary factor\n * influencing the order in which pages are delivered to the IO\n * subsystem according to empirical testing, and this is also justified\n * by considering the behavior of a buddy system containing a single\n * large block of memory acted on by a series of small allocations.\n * This behavior is a critical factor in sglist merging's success.\n *\n * -- nyc\n */\nstatic inline unsigned int expand(struct zone *zone, struct page *page, int low,\n\t\t\t\t  int high, int migratetype)\n{\n\tunsigned int size = 1 << high;\n\tunsigned int nr_added = 0;\n\n\twhile (high > low) {\n\t\thigh--;\n\t\tsize >>= 1;\n\t\tVM_BUG_ON_PAGE(bad_range(zone, &page[size]), &page[size]);\n\n\t\t/*\n\t\t * Mark as guard pages (or page), that will allow to\n\t\t * merge back to allocator when buddy will be freed.\n\t\t * Corresponding page table entries will not be touched,\n\t\t * pages will stay not present in virtual address space\n\t\t */\n\t\tif (set_page_guard(zone, &page[size], high))\n\t\t\tcontinue;\n\n\t\t__add_to_free_list(&page[size], zone, high, migratetype, false);\n\t\tset_buddy_order(&page[size], high);\n\t\tnr_added += size;\n\t}\n\n\treturn nr_added;\n}\n\nstatic __always_inline void page_del_and_expand(struct zone *zone,\n\t\t\t\t\t\tstruct page *page, int low,\n\t\t\t\t\t\tint high, int migratetype)\n{\n\tint nr_pages = 1 << high;\n\n\t__del_page_from_free_list(page, zone, high, migratetype);\n\tnr_pages -= expand(zone, page, low, high, migratetype);\n\taccount_freepages(zone, -nr_pages, migratetype);\n}\n\nstatic void check_new_page_bad(struct page *page)\n{\n\tif (unlikely(PageHWPoison(page))) {\n\t\t/* Don't complain about hwpoisoned pages */\n\t\tif (PageBuddy(page))\n\t\t\t__ClearPageBuddy(page);\n\t\treturn;\n\t}\n\n\tbad_page(page,\n\t\t page_bad_reason(page, PAGE_FLAGS_CHECK_AT_PREP));\n}\n\n/*\n * This page is about to be returned from the page allocator\n */\nstatic bool check_new_page(struct page *page)\n{\n\tif (likely(page_expected_state(page,\n\t\t\t\tPAGE_FLAGS_CHECK_AT_PREP|__PG_HWPOISON)))\n\t\treturn false;\n\n\tcheck_new_page_bad(page);\n\treturn true;\n}\n\nstatic inline bool check_new_pages(struct page *page, unsigned int order)\n{\n\tif (is_check_pages_enabled()) {\n\t\tfor (int i = 0; i < (1 << order); i++) {\n\t\t\tstruct page *p = page + i;\n\n\t\t\tif (check_new_page(p))\n\t\t\t\treturn true;\n\t\t}\n\t}\n\n\treturn false;\n}\n\nstatic inline bool should_skip_kasan_unpoison(gfp_t flags)\n{\n\t/* Don't skip if a software KASAN mode is enabled. */\n\tif (IS_ENABLED(CONFIG_KASAN_GENERIC) ||\n\t    IS_ENABLED(CONFIG_KASAN_SW_TAGS))\n\t\treturn false;\n\n\t/* Skip, if hardware tag-based KASAN is not enabled. */\n\tif (!kasan_hw_tags_enabled())\n\t\treturn true;\n\n\t/*\n\t * With hardware tag-based KASAN enabled, skip if this has been\n\t * requested via __GFP_SKIP_KASAN.\n\t */\n\treturn flags & __GFP_SKIP_KASAN;\n}\n\nstatic inline bool should_skip_init(gfp_t flags)\n{\n\t/* Don't skip, if hardware tag-based KASAN is not enabled. */\n\tif (!kasan_hw_tags_enabled())\n\t\treturn false;\n\n\t/* For hardware tag-based KASAN, skip if requested. */\n\treturn (flags & __GFP_SKIP_ZERO);\n}\n\ninline void post_alloc_hook(struct page *page, unsigned int order,\n\t\t\t\tgfp_t gfp_flags)\n{\n\tbool init = !want_init_on_free() && want_init_on_alloc(gfp_flags) &&\n\t\t\t!should_skip_init(gfp_flags);\n\tbool zero_tags = init && (gfp_flags & __GFP_ZEROTAGS);\n\tint i;\n\n\tset_page_private(page, 0);\n\n\tarch_alloc_page(page, order);\n\tdebug_pagealloc_map_pages(page, 1 << order);\n\n\t/*\n\t * Page unpoisoning must happen before memory initialization.\n\t * Otherwise, the poison pattern will be overwritten for __GFP_ZERO\n\t * allocations and the page unpoisoning code will complain.\n\t */\n\tkernel_unpoison_pages(page, 1 << order);\n\n\t/*\n\t * As memory initialization might be integrated into KASAN,\n\t * KASAN unpoisoning and memory initialization code must be\n\t * kept together to avoid discrepancies in behavior.\n\t */\n\n\t/*\n\t * If memory tags should be zeroed\n\t * (which happens only when memory should be initialized as well).\n\t */\n\tif (zero_tags)\n\t\tinit = !tag_clear_highpages(page, 1 << order);\n\n\tif (!should_skip_kasan_unpoison(gfp_flags) &&\n\t    kasan_unpoison_pages(page, order, init)) {\n\t\t/* Take note that memory was initialized by KASAN. */\n\t\tif (kasan_has_integrated_init())\n\t\t\tinit = false;\n\t} else {\n\t\t/*\n\t\t * If memory tags have not